static const SpriteData SPRITE_REGISTRY[] = {
    {"player_0", 32, 48, _sprite_player_0},
    {"player_1", 32, 48, _sprite_player_1},
    {"player_2", 32, 48, _sprite_player_2},
    {"player_3", 32, 48, _sprite_player_3},
    {"player_4", 32, 48, _sprite_player_4},
    {"player_5", 32, 48, _sprite_player_5},
    {"grass", 32, 32, _sprite_grass},
    {"dirt", 32, 32, _sprite_dirt},
    {"stone", 32, 32, _sprite_stone},
    {"iron", 32, 32, _sprite_iron},
    {"coal", 32, 32, _sprite_coal},
    {"gold", 32, 32, _sprite_gold},
    {"water", 32, 32, _sprite_water},
    {"tree", 32, 64, _sprite_tree},
    {"berry", 32, 32, _sprite_berry},
    {"clue", 32, 32, _sprite_clue},
};
static const int SPRITE_COUNT = 16;

inline const SpriteData* getSprite(const char* name) {
    for (int i = 0; i < SPRITE_COUNT; i++)
        if (__builtin_strcmp(SPRITE_REGISTRY[i].name, name) == 0)
            return &SPRITE_REGISTRY[i];
    return nullptr;
}